63: function collectSyntaxRanges(providers: FoldingRangeProvider[], model: ITextModel, cancellationToken: CancellationToken): Promise<IFoldingRangeData[] | null> {
64: 	let rangeData: IFoldingRangeData[] | null = null;
65: 	const promises = providers.map((provider, i) => {
66: 		return Promise.resolve(provider.provideFoldingRanges(model, foldingContext, cancellationToken)).then(ranges => {
67: 			if (cancellationToken.isCancellationRequested) {
68: 				return;
69: 			}
70: 			if (Array.isArray(ranges)) {
71: 				if (!Array.isArray(rangeData)) {
72: 					rangeData = [];
73: 				}
74: 				const nLines = model.getLineCount();
75: 				for (const r of ranges) {
76: 					if (r.start > 0 && r.end > r.start && r.end <= nLines) {
77: 						rangeData.push({ start: r.start, end: r.end, rank: i, kind: r.kind });
78: 					}
79: 				}
80: 			}
