import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

const ID_NAMED_REGION_PROVIDER = 'namedRegions';

export interface NamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

export class NamedRegionRangeProvider implements RangeProvider {
	readonly id = ID_NAMED_REGION_PROVIDER;

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter
	) { }

	dispose() { }

	compute(cancelationToken: CancellationToken): Promise<FoldingRegions> {
		return Promise.resolve(computeNamedRegionRanges(this.editorModel, this.foldingRangesLimit));
	}
}

// Extract region name from a line like "// #region MyName" or "/* #region MyName */"
function extractRegionName(lineContent: string): string | undefined {
	// Match #region followed by optional whitespace and then the name
	// Handle various comment styles: //, /*, #, --, <!-- etc.
	const match = lineContent.match(/#region\s+(.+?)(?:\s*(?:-->|$|\*\/))?$/i);
	if (match && match[1]) {
		return match[1].trim();
	}
	return undefined;
}

// Check if a line contains #endregion marker
function isEndregionMarker(lineContent: string): boolean {
	return /#endregion/i.test(lineContent);
}

export function computeNamedRegionRanges(
	model: ITextModel,
	foldingRangesLimit: FoldingLimitReporter,
	isComment: (line: string) => boolean = _isCommentLine
): FoldingRegions {
	const lineCount = model.getLineCount();
	const startIndexes: number[] = [];
	const endIndexes: number[] = [];
	const types: (string | undefined)[] = [];

	// Stack to track open regions: { name, startLine }
	const regionStack: { name: string; startLine: number }[] = [];

	for (let line = 1; line <= lineCount; line++) {
		const lineContent = model.getLineContent(line);

		// Check for #region marker
		const regionName = extractRegionName(lineContent);
		if (regionName !== undefined) {
			regionStack.push({ name: regionName, startLine: line });
			continue;
		}

		// Check for #endregion marker
		if (isEndregionMarker(lineContent)) {
			if (regionStack.length > 0) {
				const region = regionStack.pop()!;
				if (line > region.startLine) {
					startIndexes.push(region.startLine);
					endIndexes.push(line);
					types.push(`namedRegion:${region.name}`); // Prefix with namedRegion: to distinguish from other types
				}
			}
		}
	}

	// Convert to Uint32Array
	const limit = foldingRangesLimit.limit;
	const ranges = startIndexes.length;

	if (ranges > limit) {
		foldingRangesLimit.update(ranges, limit);
	} else {
		foldingRangesLimit.update(ranges, false);
	}

	const finalStartIndexes = new Uint32Array(Math.min(ranges, limit));
	const finalEndIndexes = new Uint32Array(Math.min(ranges, limit));
	const finalTypes: (string | undefined)[] = [];

	// Take the first 'limit' ranges
	for (let i = 0; i < Math.min(ranges, limit); i++) {
		if (startIndexes[i] > MAX_LINE_NUMBER || endIndexes[i] > MAX_LINE_NUMBER) {
			continue;
		}
		finalStartIndexes[i] = startIndexes[i];
		finalEndIndexes[i] = endIndexes[i];
		finalTypes.push(types[i]);
	}

	return new FoldingRegions(finalStartIndexes, finalEndIndexes, finalTypes);
}

/**
 * Default comment detection - checks if a line appears to be a comment
 */
function _isCommentLine(lineContent: string): boolean {
	const trimmed = lineContent.trim();
	return trimmed.startsWith('//') || trimmed.startsWith('/*') || trimmed.startsWith('*') ||
		trimmed.startsWith('#') || trimmed.startsWith('--') || trimmed.startsWith('<!--');
}

/**
 * Extract named regions from a model, returning them in order they appear
 */
export function extractNamedRegions(model: ITextModel): NamedRegion[] {
	const regions: NamedRegion[] = [];
	const lineCount = model.getLineCount();
	const regionStack: { name: string; startLine: number }[] = [];

	for (let line = 1; line <= lineCount; line++) {
		const lineContent = model.getLineContent(line);

		// Check for #region marker
		const regionName = extractRegionName(lineContent);
		if (regionName !== undefined) {
			regionStack.push({ name: regionName, startLine: line });
			continue;
		}

		// Check for #endregion marker
		if (isEndregionMarker(lineContent)) {
			if (regionStack.length > 0) {
				const region = regionStack.pop()!;
				if (line > region.startLine) {
					regions.push({
						name: region.name,
						startLineNumber: region.startLine,
						endLineNumber: line
					});
				}
			}
		}
	}

	return regions;
}

