/*---------------------------------------------------------------------------------------------
 *  Copyright (c) Microsoft Corporation. All rights reserved.
 *  Licensed under the MIT License. See License.txt in the project root for license information.
 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { computeNamedRegionRanges, extractNamedRegions } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

suite('Named Region Folding', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Extract simple named region', () => {
		const lines = [
			'// #region MySection',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MySection');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Extract multiple named regions', () => {
		const lines = [
			'// #region Section1',
			'const x = 1;',
			'// #endregion',
			'',
			'// #region Section2',
			'const y = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Section1');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		assert.strictEqual(regions[1].name, 'Section2');
		assert.strictEqual(regions[1].startLineNumber, 5);
		assert.strictEqual(regions[1].endLineNumber, 7);

		model.dispose();
	});

	test('Extract nested named regions', () => {
		const lines = [
			'// #region Outer',
			'const x = 1;',
			'// #region Inner',
			'const y = 2;',
			'// #endregion',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Inner');
		assert.strictEqual(regions[0].startLineNumber, 3);
		assert.strictEqual(regions[0].endLineNumber, 5);

		assert.strictEqual(regions[1].name, 'Outer');
		assert.strictEqual(regions[1].startLineNumber, 1);
		assert.strictEqual(regions[1].endLineNumber, 6);

		model.dispose();
	});

	test('Extract named region with different comment styles', () => {
		const lines = [
			'/* #region WithBlockComment */',
			'const x = 1;',
			'/* #endregion */'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'WithBlockComment');

		model.dispose();
	});

	test('Ignore unmatched endregion markers', () => {
		const lines = [
			'// #region Section1',
			'const x = 1;',
			'// #endregion',
			'// #endregion'  // Extra endregion without matching region
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Section1');

		model.dispose();
	});

	test('Ignore unclosed regions', () => {
		const lines = [
			'// #region Section1',
			'const x = 1;',
			'// #region Section2',
			'const y = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		// Only Section2 is closed, so only it should appear in the results
		// Note: We use a stack, so Section1 is discarded when we encounter Section2
		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Section2');

		model.dispose();
	});

	test('Extract region name with whitespace', () => {
		const lines = [
			'// #region   Section With Spaces   ',
			'const x = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const regions = extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'Section With Spaces');

		model.dispose();
	});

	test('Compute named region folding ranges', () => {
		const lines = [
			'// #region MySection',
			'const x = 1;',
			'const y = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const foldingRangesLimit = { limit: 100, update: () => { } };
		const regions = computeNamedRegionRanges(model, foldingRangesLimit);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions.getStartLineNumber(0), 1);
		assert.strictEqual(regions.getEndLineNumber(0), 4);
		assert.strictEqual(regions.getType(0), 'namedRegion:MySection');

		model.dispose();
	});

	test('Handle region markers case-insensitively', () => {
		const lines = [
			'// #REGION CaseInsensitive',
			'const x = 1;',
			'// #ENDREGION'
		];
		const model = createTextModel(lines.join('\n'));
