    49→
    50→export function computeNamedRegionRanges(
    51→	model: ITextModel,
    52→	foldingRangesLimit: FoldingLimitReporter,
    53→	isComment: (line: string) => boolean = _isCommentLine
    54→): FoldingRegions {
    55→	const lineCount = model.getLineCount();
    56→	const startIndexes: number[] = [];
    57→	const endIndexes: number[] = [];
    58→	const types: (string | undefined)[] = [];
    59→
    60→	// Stack to track open regions: { name, startLine }
    61→	const regionStack: { name: string; startLine: number }[] = [];
    62→
    63→	for (let line = 1; line <= lineCount; line++) {
    64→		const lineContent = model.getLineContent(line);
    65→
    66→		// Check for #region marker
    67→		const regionName = extractRegionName(lineContent);
    68→		if (regionName !== undefined) {
    69→			regionStack.push({ name: regionName, startLine: line });
    70→			continue;
    71→		}
    72→
    73→		// Check for #endregion marker
    74→		if (isEndregionMarker(lineContent)) {
    75→			if (regionStack.length > 0) {
    76→				const region = regionStack.pop()!;
    77→				if (line > region.startLine) {
    78→					startIndexes.push(region.startLine);
    79→					endIndexes.push(line);
    80→					types.push(`namedRegion:${region.name}`); // Prefix with namedRegion: to distinguish from other types
    81→				}
    82→			}
    83→		}
    84→	}
    85→
    86→	// Convert to Uint32Array
    87→	const limit = foldingRangesLimit.limit;
    88→	const ranges = startIndexes.length;
    89→
    90→	if (ranges > limit) {
    91→		foldingRangesLimit.update(ranges, limit);
    92→	} else {
    93→		foldingRangesLimit.update(ranges, false);
    94→	}
    95→
    96→	const finalStartIndexes = new Uint32Array(Math.min(ranges, limit));
    97→	const finalEndIndexes = new Uint32Array(Math.min(ranges, limit));
    98→	const finalTypes: (string | undefined)[] = [];
    99→
   100→	// Take the first 'limit' ranges
   101→	for (let i = 0; i < Math.min(ranges, limit); i++) {
   102→		if (startIndexes[i] > MAX_LINE_NUMBER || endIndexes[i] > MAX_LINE_NUMBER) {
   103→			continue;
   104→		}
   105→		finalStartIndexes[i] = startIndexes[i];
   106→		finalEndIndexes[i] = endIndexes[i];
