   119→		trimmed.startsWith('#') || trimmed.startsWith('--') || trimmed.startsWith('<!--');
   120→}
   121→
   122→/**
   123→ * Extract named regions from a model, returning them in order they appear
   124→ */
   125→export function extractNamedRegions(model: ITextModel): NamedRegion[] {
   126→	const regions: NamedRegion[] = [];
   127→	const lineCount = model.getLineCount();
   128→	const regionStack: { name: string; startLine: number }[] = [];
   129→
   130→	for (let line = 1; line <= lineCount; line++) {
   131→		const lineContent = model.getLineContent(line);
   132→
   133→		// Check for #region marker
   134→		const regionName = extractRegionName(lineContent);
   135→		if (regionName !== undefined) {
   136→			regionStack.push({ name: regionName, startLine: line });
   137→			continue;
   138→		}
   139→
   140→		// Check for #endregion marker
   141→		if (isEndregionMarker(lineContent)) {
   142→			if (regionStack.length > 0) {
   143→				const region = regionStack.pop()!;
   144→				if (line > region.startLine) {
   145→					regions.push({
   146→						name: region.name,
   147→						startLineNumber: region.startLine,
   148→						endLineNumber: line
   149→					});
   150→				}
   151→			}
   152→		}
   153→	}
   154→
